function solve(n: number, edges: number[][], label: string): number {
    const graph: number[][] = new Array(n).fill(0).map(() => new Array<number>());

    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    const visited = new Array(n).fill(false);
    let maxLength = 0;

    function dfs(node: number, path: number[], visited: boolean[]): void {
        visited[node] = true;
        path.push(node);

        // Check if current path can form a palindrome
        const start = 0;
        const end = path.length - 1;
        let isPalindrome = true;
        while (start < end) {
            if (label[path[start]] !== label[path[end]]) {
                isPalindrome = false;
                break;
            }
            start++;
            end--;
        }

        if (isPalindrome) {
            maxLength = Math.max(maxLength, path.length);
        }

        // Explore neighbors
        for (const neighbor of graph[node]) {
            if (!visited[neighbor]) {
                dfs(neighbor, path, visited);
            }
        }

        path.pop();
        visited[node] = false;
    }

    for (let i = 0; i < n; i++) {
        const visitedCopy = [...visited];
        dfs(i, [i], visitedCopy);
    }

    return maxLength;
}

